export function getProducts(_lang?: string): Product[] { return products; }
export function getProductById(id: number): Product | undefined { return products.find(p => p.id === id); }
export function getFeaturedProducts(count?: number): Product[] { return products.filter(p => p.rating >= 4.8).slice(0, count || 12); }
export function getProductsByCategory(cat: string): Product[] { return cat === 'all' ? products : products.filter(p => p.category === cat); }
export function getRelatedProducts(id: number, count?: number): Product[] { 
  const product = products.find(p => p.id === id);
  if (!product) return [];
  return products.filter(p => p.id !== id && p.category === product.category).slice(0, count || 4);
}
export function getTrendingProducts(count?: number): Product[] { return products.filter(p => p.reviews > 300).slice(0, count || 12); }
export function getNewArrivals(count?: number): Product[] { return products.slice(-(count || 12)).reverse(); }
export function searchProducts(query: string): Product[] {
  const q = query.toLowerCase();
  return products.filter(p => p.title.toLowerCase().includes(q) || p.description.toLowerCase().includes(q));
}
export const baseProducts = products;
export default products;
